exercises.solution_code:
#include <iostream>

struct Rectangle {
    int width{};
    int height{};

    Rectangle(int w, int h) : width{w}, height{h} {}

    int area() const {
        return width * height;
    }

    int perimeter() const {
        return 2 * (width + height);
    }
};

void print_stats(Rectangle r) {
    std::cout << "Area: " << r.area() << "\n";
    std::cout << "Perimeter: " << r.perimeter() << "\n";
}

int main() {
    int w{}, h{};
    std::cin >> w >> h;

    // Pass a temporary Rectangle to print_stats — no named variable.
    print_stats(Rectangle{w, h});

    // Call a member function directly on a temporary (result discarded).
    (void)Rectangle{w, h}.area();

    return 0;
}

