exercises.solution_code:
#include <iostream>

struct Point {
    int x{};
    int y{};

    Point(int px, int py) : x{px}, y{py} {}

    int dist_sq() const {
        return x * x + y * y;
    }
};

Point closest_to_origin(Point a, Point b) {
    return (b.dist_sq() < a.dist_sq()) ? b : a;
}

int main() {
    int n{};
    std::cin >> n;

    int fx{}, fy{};
    std::cin >> fx >> fy;
    Point best{fx, fy};  // named variable for the running best

    for (int i{1}; i < n; ++i) {
        int x{}, y{};
        std::cin >> x >> y;
        // Pass a temporary Point — no named variable inside the loop
        best = closest_to_origin(best, Point{x, y});
    }

    std::cout << "Closest: (" << best.x << ", " << best.y << ")\n";

    return 0;
}
